private final static int _parseIndex(String str) {
    final int len = str.length();
    if (len == 0 || len > 10) {
        return -1;
    }

    boolean flag = true;
    for (int i = 0; i < len && flag; ++i) {
        char c = str.charAt(i);
        if (c == '0'){
        	if ((i + 1 != len)){
        		flag = false;
        	}

        }else if (c > '9' || c < '0') {
            return -1;
        }
    }

    if (!flag){
        return -1;
    }

    if (len == 10) {
        long l = NumberInput.parseLong(str);
        if (l > Integer.MAX_VALUE) {
            return -1;
        }
    }

    return NumberInput.parseInt(str);
}

